```typescript
import { NextRequest } from "next/server";
import { z } from "zod";

import { prisma } from "@rlm-saas/database";

import { requireAuth } from "@/lib/auth";
import { successResponse, handleError } from "@/lib/api/responses";

// Query parameters validation schema
const getUsersQuerySchema = z.object({
  limit: z.coerce.number().min(1).max(100).default(50),
  offset: z.coerce.number().min(0).default(0),
  search: z.string().optional(),
  status: z.enum(["active", "inactive", "banned"]).optional(),
  teamId: z.string().optional(),
});

export async function GET(request: NextRequest): Promise<Response> {
  try {
    // 1. Authenticate user
    const user = await requireAuth();

    // 2. Validate query parameters
    const searchParams = request.nextUrl.searchParams;
    const queryParams = getUsersQuerySchema.parse({
      limit: searchParams.get("limit"),
      offset: searchParams.get("offset"),
      search: searchParams.get("search"),
      status: searchParams.get("status"),
      teamId: searchParams.get("teamId"),
    });

    // 3. Build where clause
    const where: any = {};

    if (queryParams.search) {
      where.OR = [
        { name: { contains: queryParams.search, mode: "insensitive" } },
        { email: { contains: queryParams.search, mode: "insensitive" } },
      ];
    }

    if (queryParams.status) {
      where.status = queryParams.status;
    }

    if (queryParams.teamId) {
      where.teamMemberships = {
        some: {
          teamId: queryParams.teamId,
        },
      };
    }

    // 4. Query database
    const [users, total] = await Promise.all([
      prisma.user.findMany({
        where,
        select: {
          id: true,
          name: true,
          email: true,
          image: true,
          status: true,
          createdAt: true,
          updatedAt: true,
          _count: {
            select: {
              teamMemberships: true,
              projects: true,
            },
          },
        },
        orderBy: { createdAt: "desc" },
        take: queryParams.limit,
        skip: queryParams.offset,
      }),
      prisma.user.count({ where }),
    ]);

    // 5. Return response
    return successResponse({
      users,
      total,
      hasMore: queryParams.offset + queryParams.limit < total,
      pagination: {
        limit: queryParams.limit,
        offset: queryParams.offset,
      },
    });
  } catch (error) {
    return handleError(error);
  }
}
```

